mapper.select:
select * from view_community_feed
order by member_count desc, created_datetime desc
limit #{criteria.count} offset #{criteria.offset}

select v.* from view_community_feed v
join tbl_community_member cm on cm.community_id = v.id
where cm.member_id = #{memberId}
order by cm.joined_at desc
limit #{criteria.count} offset #{criteria.offset}

select * from view_community_feed
where category_id = #{categoryId}
order by member_count desc, created_datetime desc
limit #{criteria.count} offset #{criteria.offset}

mapper.sql:
left join (select post_id, count(*) as cnt from tbl_post_like group by post_id) lc on lc.post_id = p.id
left join (select reply_post_id, count(*) as cnt from tbl_post where post_status = 'active' and reply_post_id is not null group by reply_post_id) rc on rc.reply_post_id = p.id
left join (select post_id, count(*) as cnt from tbl_bookmark group by post_id) bc on bc.post_id = p.id
left join tbl_post_like pl2 on pl2.post_id = p.id and pl2.member_id = #{memberId}
left join tbl_bookmark bk2 on bk2.post_id = p.id and bk2.member_id = #{memberId}
